sys_script_include.script:
/**
 * TableFilterApplier
 *
 * Responsible for applying filter clauses to GlideRecord objects.
 * Handles encoded query building and logical operator combination.
 *
 * @class
 */
var TableFilterApplier = Class.create();
TableFilterApplier.prototype = {
    initialize: function (params) {
        params = params || {};
        this.logger = params.logger;
        this.configObject = params.configObject || {};
        this.queryBuilder = params.queryBuilder;
    },

    /**
     * Apply filters to a GlideRecord or GlideAggregate.
     *
     * @param {GlideRecord|GlideAggregate} glideRecord
     * @param {Array} filters
     */
    applyFilters: function (glideRecord, filters) {
        filters = filters || [];

        if (
            !glideRecord ||
            typeof glideRecord.addQuery !== "function" ||
            typeof glideRecord.addEncodedQuery !== "function"
        ) {
            if (this.logger) {
                this.logger.warn({
                    method: "applyFilters",
                    message: "Invalid GlideRecord provided for filtering",
                });
            }
            return;
        }

        if (this.configObject.static_query) {
            glideRecord.addEncodedQuery(this.configObject.static_query);
        }

        var encodedFilters = "";

        for (var i = 0; i < filters.length; i++) {
            var filter = filters[i];
            var clause = this.queryBuilder.buildEncodedFilterClause(filter);

            if (!clause) {
                continue;
            }

            if (!encodedFilters) {
                encodedFilters = clause;
                continue;
            }

            // Use the logicalOperator from the PREVIOUS filter to determine how to connect
            var prevFilter = filters[i - 1];
            var logicalOperator = String(prevFilter.logicalOperator || "and")
                .toLowerCase()
                .trim();

            encodedFilters +=
                logicalOperator === "or" ? "^OR" + clause : "^" + clause;
        }

        if (encodedFilters) {
            glideRecord.addEncodedQuery(encodedFilters);
        }
    },

    /**
     * Apply a single operator filter to a GlideRecord.
     * Legacy method, kept for compatibility.
     *
     * @param {GlideRecord} glideRecord
     * @param {Object} filter
     * @param {string} operator
     */
    applyOperatorFilter: function (glideRecord, filter, operator) {
        var field = filter.field;
        var value = filter.value;
        var valueTo = filter.valueTo;
        var queryField = field;

        if (
            filter.type === "reference" &&
            this.queryBuilder.isReferenceTextOperator(operator)
        ) {
            queryField = this.queryBuilder.resolveReferenceTextQueryField(
                filter,
                operator,
            );
        }

        if (operator === "is_anything") {
            return;
        }

        if (operator === "is_empty") {
            glideRecord.addEncodedQuery(queryField + "ISEMPTY");
            return;
        }

        if (operator === "is_not_empty") {
            glideRecord.addEncodedQuery(queryField + "ISNOTEMPTY");
            return;
        }

        if (operator === "between") {
            if (value != null && String(value) !== "") {
                var encodedRange = String(value);
                if (valueTo != null && String(valueTo) !== "") {
                    encodedRange += "@" + String(valueTo);
                }
                glideRecord.addQuery(queryField, "BETWEEN", encodedRange);
            }
            return;
        }

        var glideOperator = this.queryBuilder.OPERATOR_MAP[operator];
        if (!glideOperator) {
            if (this.logger) {
                this.logger.warn({
                    method: "applyOperatorFilter",
                    message: "Unsupported operator",
                    operator: operator,
                    filter: filter,
                });
            }
            return;
        }

        if (operator === "is_empty_string") {
            glideRecord.addQuery(queryField, glideOperator, "");
            return;
        }

        glideRecord.addQuery(queryField, glideOperator, value);
    },

    type: "TableFilterApplier",
};
